-- Drop existing table
DROP TABLE IF EXISTS public.chats CASCADE;

-- Create table with exact schema
CREATE TABLE public.chats (
    id uuid NOT NULL DEFAULT gen_random_uuid(),
    user_id uuid NOT NULL,
    exercice_id uuid,
    session_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    chat_type text DEFAULT 'exercice'::text,
    titre text,
    exercise_context jsonb DEFAULT '{}'::jsonb,
    CONSTRAINT chats_pkey PRIMARY KEY (id),
    CONSTRAINT chats_exercice_id_key UNIQUE (exercice_id)
);

-- Foreign Keys: None

-- Create indexes
CREATE INDEX idx_chats_user_id ON public.chats USING btree (user_id);
CREATE INDEX idx_chats_exercice_id ON public.chats USING btree (exercice_id);
CREATE INDEX idx_chats_session_id ON public.chats USING btree (session_id);
CREATE INDEX idx_chats_chat_type ON public.chats USING btree (chat_type);

-- Enable Row Level Security
ALTER TABLE public.chats ENABLE ROW LEVEL SECURITY;

-- Create RLS policies
CREATE POLICY "Users can delete their own chats" ON public.chats
    FOR DELETE USING (auth.uid() = user_id);

CREATE POLICY "Users can insert their own chats" ON public.chats
    FOR INSERT WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can update their own chats" ON public.chats
    FOR UPDATE USING (auth.uid() = user_id);

CREATE POLICY "Users can view their own chats" ON public.chats
    FOR SELECT USING (auth.uid() = user_id);

-- Create trigger for updated_at
-- Note: Assumes update_updated_at_column() function already exists
CREATE TRIGGER update_chats_updated_at
    BEFORE UPDATE ON public.chats
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

