INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('0c5620bf-e363-4b9b-9d2d-b1ee30886f98'::uuid, '255895dc-667d-4d27-a57f-5dfa2e131af0'::uuid, '14bc69e5-9fb8-4fb7-8475-fa1e7d861f9e'::uuid, 'e920336c-ccd3-45b5-bc66-254e2197cfad'::uuid, '2025-12-14T15:50:53.169306+00:00'::timestamp with time zone, '2025-12-15T20:50:03.881846+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Polynômes du second degré', '{"derniere_maj":"2025-12-14T16:02:24.359Z","resolution_eleve":"1. x^2 - x - 1 = 0\n\\Delta = 1+4=5 \\quad x_1 = \\frac{1+\\sqrt{5}}{2} \\quad x_2 = \\frac{1-\\sqrt{5}}{2}\n\nje retrouve \\varphi = \\frac{1+\\sqrt{5}}{2}\n\n2. Si \\varphi est solution de l''équation\nalors \\varphi^2 - \\varphi - 1 = 0 \\quad donc\n\\varphi^2 = \\varphi + 1\n\n3. u_{n+1} = \\varphi^{n+1} \\quad u_{n+2} = \\varphi^{n+2}\n\nu_{n+1} + u_{n+2} = \\varphi^{n+1} + \\varphi^{n+2}\n= \\varphi^{2n+3}\n\nje ne trouve pas le bon résultat\n\n4. je ne comprends pas la question\n\n5. F_0 = 0, F_1 = 1, F_2 = 1+0 = 1\nF_3 = F_2 + F_1 = 1+1 = 2\n\nF_4 = F_3 + F_2 = 2+1 = 3","corrections_remarques":"❌ Erreur de raisonnement à la question 3. La simplification de `\\varphi^{n+1} + \\varphi^{n+2}` en `\\varphi^{2n+3}` est incorrecte. L''addition de puissances ne suit pas la règle d''addition des exposants."}'::jsonb),
    ('9d56c464-a3c4-490f-9d49-a6d475864c4b'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, '56bda214-500e-4959-84ea-192a67e602e2'::uuid, '79b7499c-774b-45e6-a646-e88154dc967d'::uuid, '2025-12-14T16:30:29.916419+00:00'::timestamp with time zone, '2025-12-14T16:30:29.916419+00:00'::timestamp with time zone, 'exercice', NULL, '{}'::jsonb);
