INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('314284ba-dbbc-452b-9b3d-f2a8ad1c850c'::uuid, '255895dc-667d-4d27-a57f-5dfa2e131af0'::uuid, '0f244efe-3b7d-42d2-adef-388ff29de117'::uuid, 'e920336c-ccd3-45b5-bc66-254e2197cfad'::uuid, '2025-12-15T20:50:03.998157+00:00'::timestamp with time zone, '2025-12-15T20:59:27.868128+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Dérivation', '{"derniere_maj":"2025-12-15T20:59:27.732Z","resolution_eleve":"f(x) = x^3 - 3x^2 + 4\n\n1. f''(x) = 3x^2 - 6x = 3x(x-2)\n\n2. \\begin{array}{c|ccccccc}\nx & -\\infty & & 0 & & 2 & & +\\infty \\\\\n\\hline\n3x^2-6x & & + & 0 & - & 0 & + & \\\\\n\\hline\n\\text{var } f & & \\nearrow & 4 & \\searrow & 0 & \\nearrow & \\\\\n\\end{array}\n\n3. \\text{maximum local : } f(0) = 4 \\\\\n\\text{minimum local : } f(2) = 0\n\n4. (T_1): y = f''(1)(x-1) + f(1) \\\\\ny = -3(x-1) + 2\n\n5. (T_0): y = f''(0)(x-0) + f(0) \\\\\ny = 0(x-0) + 4","corrections_remarques":"✅ Travail correct"}'::jsonb),
    ('e62be1a7-7723-43ec-b4e4-592f131865af'::uuid, '255895dc-667d-4d27-a57f-5dfa2e131af0'::uuid, '5bdd6802-efa8-4121-af82-52370f1b1648'::uuid, 'e920336c-ccd3-45b5-bc66-254e2197cfad'::uuid, '2025-12-15T20:59:27.952913+00:00'::timestamp with time zone, '2025-12-15T21:07:21.633986+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Dérivation', '{}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('4c808627-a480-4ac4-837f-c2b0ed058cbb'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, NULL, '79b7499c-774b-45e6-a646-e88154dc967d'::uuid, '2025-12-15T21:00:24.719293+00:00'::timestamp with time zone, '2025-12-15T21:00:24.719293+00:00'::timestamp with time zone, 'cours', 'Je veux un exo de suites vraiment dur', '{}'::jsonb),
    ('f0e49880-72f5-43bb-aa1f-f9cb16e5c9f7'::uuid, '306093a9-efc0-4370-a917-35ca259ae261'::uuid, 'fbfdd83b-b0e4-4f20-a78d-841a5abb4d97'::uuid, '79b7499c-774b-45e6-a646-e88154dc967d'::uuid, '2025-12-15T21:00:46.661883+00:00'::timestamp with time zone, '2025-12-15T21:06:19.215354+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Compléments sur la dérivation', '{"derniere_maj":"2025-12-15T21:06:12.146Z","enonce_exercice":"\\textbf{Énoncé de l''exercice}\n\n\\textbf{Contexte :}\n\nSoit la fonction $f$ définie sur $\\mathbb{R}$ par $f(x) = x^3 - 3x^2 + 4$. On note $C_f$ sa courbe représentative dans un repère orthogonal.\n\n\\textbf{Questions :}\n\n\\begin{enumerate}\n    \\item Calcule la dérivée $f''(x)$ de la fonction $f$.\n    \\item Étudie le signe de $f''(x)$ et déduis-en les variations de la fonction $f$.\n    \\item Calcule les extremums locaux de $f$ (valeurs et positions).\n    \\item Détermine l''équation de la tangente à la courbe $C_f$ au point d''abscisse $x = 1$.\n    \\item Détermine l''équation de la tangente à la courbe $C_f$ au point d''abscisse $x = 0$.\n\\end{enumerate}"}'::jsonb);
