INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('5d9ae9f7-0702-45ed-887d-908bea0c0037'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-19T22:03:16.693852+00:00'::timestamp with time zone, '2025-12-19T22:08:16.947064+00:00'::timestamp with time zone, 'exercice', 'Exercice : Repérage dans l''espace', '{"derniere_maj":"2025-12-19T22:08:16.753Z","resolution_eleve":"Exo: Domaine de définition et dérivée de f(x) = \\frac{\\sqrt{x}}{1+\\frac{1}{\\sqrt{x}}} \\\\ \\\\ f \\text{ est définie sur } \\mathbb{R}_+. \\\\ \\text{Dérivée: } f''(x) = \\frac{\\frac{1}{2\\sqrt{x}}(1+\\frac{1}{\\sqrt{x}}) - \\sqrt{x} \\times -\\frac{1}{2}x^{-3/2}}{\\left(1+\\frac{1}{\\sqrt{x}}\\right)^2} \\\\ \\\\ f''(x) = \\frac{\\frac{1}{2x} + \\frac{1}{2\\sqrt{x}} + \\frac{1}{2x}}{\\left(1+\\frac{1}{\\sqrt{x}}\\right)^2} = \\frac{\\frac{1}{x} + \\frac{1}{2\\sqrt{x}}}{\\left(1+\\frac{1}{\\sqrt{x}}\\right)^2}","corrections_remarques":"1. ❌ Le domaine de définition est incorrect. Il est ]0, +inf[ et non [0, +inf[ (noté R+) car la fonction n''est pas définie en x=0.\n\n📝 Correction: Le domaine de définition est Df = ]0, +inf[. Le calcul de la dérivée est correct."}'::jsonb),
    ('c91c1ab8-3cfd-4e35-adc9-6dc20513a70e'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-19T22:25:34.799285+00:00'::timestamp with time zone, '2025-12-19T22:25:34.799285+00:00'::timestamp with time zone, 'exercice', 'Exercice : Compléments sur la dérivation', '{}'::jsonb);
