INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('ed0c76ed-0709-4d5d-a9b6-af4db3b4129b'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-20T17:10:51.097181+00:00'::timestamp with time zone, '2025-12-20T17:11:33.167515+00:00'::timestamp with time zone, 'exercice', 'c''est correct ce que j''ai fait?', '{"derniere_maj":"2025-12-20T17:11:32.965Z","resolution_eleve":"Exo: Domaine de définition et dérivée de f(x) = \\frac{\\sqrt{x}}{1+\\frac{1}{\\sqrt{x}}}\n\nf est définie sur R+.\nDérivée: f''(x) = \\frac{\\frac{1}{2\\sqrt{x}}(1+\\frac{1}{\\sqrt{x}}) - \\sqrt{x} \\times -\\frac{1}{2}x^{-3/2}}{(1+\\frac{1}{\\sqrt{x}})^2}\n\nf''(x) = \\frac{\\frac{1}{2x} + \\frac{1}{2\\sqrt{x}} + \\frac{1}{2x}}{(1+\\frac{1}{\\sqrt{x}})^2} = \\frac{\\frac{1}{x} + \\frac{1}{2\\sqrt{x}}}{(1+\\frac{1}{\\sqrt{x}})^2}","corrections_remarques":"1. ❌ Le domaine de définition est incorrect. Il est R+* (]0, +∞[) et non R+ ([0, +∞[) car x ne peut pas être égal à 0 à cause du terme 1/sqrt(x).\n\n📝 Correction: Le domaine de définition est R+* (]0, +∞[) car x=0 est une valeur interdite. Le calcul de la dérivée est correct."}'::jsonb),
    ('3e497862-5668-4aab-9c8b-3ec4032b8c66'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-20T17:13:12.154115+00:00'::timestamp with time zone, '2025-12-20T17:13:28.701383+00:00'::timestamp with time zone, 'exercice', '📸 Exercice soumis via image', '{"derniere_maj":"2025-12-20T17:13:28.578Z","enonce_exercice":"EXERCICE 2 \\hfill 5 points\n\nUn des objectifs de cet exercice est de déterminer une approximation du nombre réel\nln(2), en utilisant une des méthodes du mathématicien anglais Henry Briggs au XVIe\nsiècle.\n\nOn désigne par $(u_n)$ la suite définie par :\n\n$u_0 = 2$ et, pour tout entier naturel $n$, $u_{n+1} = \\sqrt{u_n}$\n\n\\textbf{Partie A}\n\n1. a. Donner la valeur exacte de $u_1$ et de $u_2$.\n   b. Émettre une conjecture, à l''aide de la calculatrice, sur le sens de variation et la limite éventuelle de la suite.\n\n2. a. Montrer par récurrence que pour tout entier naturel $n$, $1 \\le u_{n+1} \\le u_n$.\n   b. En déduire que la suite $(u_n)$ est convergente.\n   c. Résoudre dans l''intervalle $[0; +\\infty[$ l''équation $\\sqrt{x} = x$.\n   d. Déterminer, en justifiant, la limite de la suite $(u_n)$."}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('57bdfe11-718d-426d-9eda-bce683c960cf'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-20T17:22:13.690431+00:00'::timestamp with time zone, '2025-12-20T17:22:27.522115+00:00'::timestamp with time zone, 'exercice', 'voilà l''énoncé d''un exo, aide-moi pour le faire', '{"derniere_maj":"2025-12-20T17:22:27.455Z","enonce_exercice":"EXERCICE 2 \\hfill 5 points\n\nUn des objectifs de cet exercice est de déterminer une approximation du nombre réel\nln(2), en utilisant une des méthodes du mathématicien anglais Henry Briggs au XVI^e\nsiècle.\n\nOn désigne par $(u_n)$ la suite définie par :\n\n$u_0 = 2$ et, pour tout entier naturel n, $u_{n+1} = \\sqrt{u_n}$\n\n\\textbf{Partie A}\n\n1. \\quad a. Donner la valeur exacte de $u_1$ et de $u_2$.\n   \\quad b. Émettre une conjecture, à l''aide de la calculatrice, sur le sens de variation et la limite éventuelle de la suite.\n\n2. \\quad a. Montrer par récurrence que pour tout entier naturel n, $1 \\le u_{n+1} \\le u_n$.\n   \\quad b. En déduire que la suite $(u_n)$ est convergente.\n   \\quad c. Résoudre dans l''intervalle $[0; +\\infty[$ l''équation $\\sqrt{x} = x$.\n   \\quad d. Déterminer, en justifiant, la limite de la suite $(u_n)$."}'::jsonb),
    ('715c176d-d24a-4eba-9430-de59f3444344'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2025-12-20T17:39:46.293043+00:00'::timestamp with time zone, '2025-12-20T17:39:46.293043+00:00'::timestamp with time zone, 'exercice', 'tu peux m''expliquer comment on fait une récurrence...', '{}'::jsonb);
