INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('12e3a0db-6134-48ce-8694-a881dd91319c'::uuid, '400bfb6a-df9f-4d59-bfcc-ec1fe33a5807'::uuid, NULL, '93c7b8a5-aca9-47b2-aab4-8f9399b78509'::uuid, '2026-01-02T15:15:01.488104+00:00'::timestamp with time zone, '2026-01-02T15:15:20.745098+00:00'::timestamp with time zone, 'exercice', '📸 Exercice soumis via image', '{"derniere_maj":"2026-01-02T15:15:20.507Z","enonce_exercice":"66 Dans chacun des cas ci-dessous, u est une suite géométrique de raison q > 0. Déterminer la valeur de q, le terme initial u_0, puis exprimer le terme général u_n.\n\n1. u_2 = 4, u_6 = 64\n\n2. u_3 = 250, u_8 = 781250\n\n3. u_4 = \\frac{3}{8}, u_{10} = \\frac{3}{512}\n\n4. u_4 = \\frac{1}{9}, u_7 = \\frac{1}{243}"}'::jsonb),
    ('05bb7c34-d827-4746-924c-a4770a6eb96e'::uuid, '400bfb6a-df9f-4d59-bfcc-ec1fe33a5807'::uuid, 'ba3b7c41-01ba-4108-8f14-36d895e46173'::uuid, '93c7b8a5-aca9-47b2-aab4-8f9399b78509'::uuid, '2026-01-02T15:15:20.83247+00:00'::timestamp with time zone, '2026-01-02T15:15:20.83247+00:00'::timestamp with time zone, 'exercice', NULL, '{}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('b209faf6-d1ec-4358-abbe-7f46febf142f'::uuid, '1e6d88c3-5ca8-4091-afba-05b47b40da66'::uuid, NULL, '2545ab9e-74bd-444f-8af3-351c6ff45c5e'::uuid, '2026-01-06T13:01:55.004552+00:00'::timestamp with time zone, '2026-01-06T13:03:25.175689+00:00'::timestamp with time zone, 'exercice', '📸 Exercice soumis via image', '{"derniere_maj":"2026-01-06T13:02:34.059Z","enonce_exercice":"98 \\quad \\text{CALCULER} \\quad \\text{RAISONNER}\n\n\\text{Le nombre d''abonnés à un journal (en milliers) est donné par la fonction } f \\text{ définie sur } [0; +\\infty[ \\text{ par } f(x) = 3e^{-0,1x^2+0,7x} \\text{ où } x \\text{ est le temps (en années) écoulé depuis le 1er janvier 2015. On nomme } \\mathcal{C}_f \\text{ la courbe représentative de } f.\n\n\\text{1. a. Justifier que, pour tout réel } x \\text{ de } [0; +\\infty[ :}\n\\[1em]\nf(x) = 3e^{x(-0,1x+0,7)}.\n\n\\text{b. Calculer la limite de } f \\text{ en } +\\infty.\n\n\\text{c. Interpréter graphiquement ce résultat.}\n\n\\text{2. Calculer } f''(x) \\text{ pour tout réel } x \\text{ de } [0; +\\infty[.\n\n\\text{3. Construire le tableau de variation de la fonction } f \\text{ sur } [0; +\\infty[.\n\n\\text{4. Déterminer, à la dizaine près, le nombre maximal d''abonnés au journal.}\n\n\\text{Au cours de quelle année ce nombre sera-t-il atteint ?}"}'::jsonb),
    ('4069a2b0-fbc8-4f80-bb0b-8e0f1e5bb072'::uuid, '1e6d88c3-5ca8-4091-afba-05b47b40da66'::uuid, '9a65b2a8-79f3-49c6-b44c-55f8215e73e4'::uuid, '2545ab9e-74bd-444f-8af3-351c6ff45c5e'::uuid, '2026-01-06T13:03:25.604247+00:00'::timestamp with time zone, '2026-01-06T13:07:34.35701+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Compléments sur la dérivation', '{"derniere_maj":"2026-01-06T13:02:34.059Z","enonce_exercice":"98 \\quad \\text{CALCULER} \\quad \\text{RAISONNER}\n\n\\text{Le nombre d''abonnés à un journal (en milliers) est donné par la fonction } f \\text{ définie sur } [0; +\\infty[ \\text{ par } f(x) = 3e^{-0,1x^2+0,7x} \\text{ où } x \\text{ est le temps (en années) écoulé depuis le 1er janvier 2015. On nomme } \\mathcal{C}_f \\text{ la courbe représentative de } f.\n\n\\text{1. a. Justifier que, pour tout réel } x \\text{ de } [0; +\\infty[ :}\n\\[1em]\nf(x) = 3e^{x(-0,1x+0,7)}.\n\n\\text{b. Calculer la limite de } f \\text{ en } +\\infty.\n\n\\text{c. Interpréter graphiquement ce résultat.}\n\n\\text{2. Calculer } f''(x) \\text{ pour tout réel } x \\text{ de } [0; +\\infty[.\n\n\\text{3. Construire le tableau de variation de la fonction } f \\text{ sur } [0; +\\infty[.\n\n\\text{4. Déterminer, à la dizaine près, le nombre maximal d''abonnés au journal.}\n\n\\text{Au cours de quelle année ce nombre sera-t-il atteint ?}"}'::jsonb);
