    ('58ffbd34-fd4f-420d-bfba-f595f4a16899'::uuid, '255895dc-667d-4d27-a57f-5dfa2e131af0'::uuid, '1a34c804-145f-4143-b279-ae84a05827f3'::uuid, 'e920336c-ccd3-45b5-bc66-254e2197cfad'::uuid, '2026-01-11T11:02:02.243481+00:00'::timestamp with time zone, '2026-01-11T11:03:26.501998+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Suites numériques', '{}'::jsonb),
