INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('d06db598-718c-408d-ac06-9971209c5666'::uuid, '31fca5c9-e001-4fda-920f-9bfb90451d84'::uuid, NULL, '71ce2595-627d-4aa2-a5cb-10a47dd68053'::uuid, '2026-01-12T19:48:20.682358+00:00'::timestamp with time zone, '2026-01-12T20:22:29.901992+00:00'::timestamp with time zone, 'exercice', 'Je n’arrive pas à faire la question 3.b de l’exerc...', '{"derniere_maj":"2026-01-12T19:49:14.434Z","enonce_exercice":"Exercice 3 : (6 points)\n\nOn considère la suite $(u_n)$ définie, pour tout entier naturel non nul, par :\n$$ u_n = \\frac{n(n+2)}{(n+1)^2} $$\n\nLa suite $(v_n)$ est définie par :\n$v_1 = u_1, v_2 = u_1 \\times u_2$ et pour tout entier naturel $n \\ge 3, v_n = u_1 \\times u_2 \\times \\dots \\times u_n = v_{n-1} \\times u_n$.\n\n1. Vérifier que l''on a $v_2 = \\frac{2}{3}$ puis calculer $v_3$.\n\n2. On considère l''algorithme incomplet ci-dessous. Recopier et compléter sur la copie cet algorithme afin que, après son exécution, la variable V contienne la valeur $v_n$ où $n$ est un nombre entier naturel non nul définie par l''utilisateur.\nAucune justification n''est attendue.\n\n\\begin{center}\n\\begin{tabular}{|l|l|}\n\\hline\n\\multicolumn{2}{|c|}{Algorithme} \\\\\n\\hline\n1. & $V \\leftarrow 1$ \\\\\n2. & Pour $i$ variant de 1 à $n$ \\\\\n3. & $V \\leftarrow V \\times i(i+2)/(i+1)^2$ \\\\\n4. & $V \\leftarrow \\dots$ \\\\\n5. & Fin Pour \\\\\n\\hline\n\\end{tabular}\n\\end{center}\n\n3. a. Montrer que, pour tout entier naturel non nul, $u_n = 1 - \\frac{1}{(n+1)^2}$.\nb. Montrer que, pour tout entier naturel non nul, $0 < u_n < 1$."}'::jsonb),
    ('43a3b997-c415-4fc1-9555-d00977ee00e4'::uuid, '31fca5c9-e001-4fda-920f-9bfb90451d84'::uuid, '292b234e-ce3a-406c-bb71-e7226ae4fe36'::uuid, '71ce2595-627d-4aa2-a5cb-10a47dd68053'::uuid, '2026-01-12T20:22:30.412066+00:00'::timestamp with time zone, '2026-01-13T16:53:28.597856+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Suites numériques', '{"derniere_maj":"2026-01-13T16:53:28.387Z","enonce_exercice":"\\text{Partie 2}\n\nOn note (E) l''équation différentielle y'' = -y + e^{-x}.\n\nOn admet que g : x \\mapsto xe^{-x} est une solution particulière de (E).\n\n1. Donner toutes les solutions sur \\mathbb{R} de l''équation différentielle (H) : y'' = -y.\n\n2. En déduire toutes les solutions sur \\mathbb{R} de l''équation différentielle (E).\n\n3. Sachant que la fonction f est la solution particulière de (E) qui vérifie f(0) = 2, déterminer une expression de f(x) en fonction de x.\n\n\\text{Partie 3}\n\nOn admet que pour tout nombre réel x, f(x) = (x+2)e^{-x}.\n\n1. a. Montrer que pour tout x \\in \\mathbb{R}, f''(x) = (-x-1)e^{-x}.\n\n   b. Etudier le signe de f''(x) pour tout x \\in \\mathbb{R} et dresser le tableau de variations complet de f sur \\mathbb{R}."}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('e718a142-c0e3-46c0-946d-20a93ed375df'::uuid, 'e732120d-bb2d-4671-840d-2f74213bf0cc'::uuid, NULL, '4613146e-b064-4115-a1af-a2831d1e6dc4'::uuid, '2026-01-12T20:51:55.117955+00:00'::timestamp with time zone, '2026-01-12T20:52:21.634021+00:00'::timestamp with time zone, 'exercice', 'Aide moi pour la 4)a)', '{"derniere_maj":"2026-01-12T20:52:21.367Z","enonce_exercice":"Exercice 3 : (6 points)\n\nOn considère la suite $(u_n)$ définie, pour tout entier naturel non nul, par :\n$$ u_n = \\frac{n(n+2)}{(n+1)^2} $$\n\nLa suite $(v_n)$ est définie par :\n$v_1 = u_1$, $v_2 = u_1 \\times u_2$ et pour tout entier naturel $n \\ge 3$, $v_n = u_1 \\times u_2 \\times \\dots \\times u_n = v_{n-1} \\times u_n$.\n\n1. Vérifier que l''on a $v_2 = \\frac{2}{3}$ puis calculer $v_3$.\n\n2. On considère l''algorithme incomplet ci-dessous. Recopier et compléter sur la copie cet algorithme afin que, après son exécution, la variable V contienne la valeur $v_n$ où n est un nombre entier naturel non nul définie par l''utilisateur. Aucune justification n''est attendue.\n\n\\begin{tabular}{|ll|}\n\\hline\n& Algorithme \\\\\n1. & V $\\leftarrow$ 1 \\\\\n2. & Pour i variant de 1 à n \\\\\n3. & U $\\leftarrow \\frac{...(...+2)}{(...+1)^2}$ \\\\\n4. & V $\\leftarrow ...$ \\\\\n5. & Fin Pour \\\\\n\\hline\n\\end{tabular}\n\n3. a. Montrer que, pour tout entier naturel non nul, $u_n = 1 - \\frac{1}{(n+1)^2}$.\n   b. Montrer que, pour tout entier naturel non nul n, $0 < u_n < 1$.\n\n4. a. Montrer que la suite $(v_n)$ est décroissante.\n   b. Justifier que la suite $(v_n)$ est convergente (on ne demande pas de calculer sa limite).\n\n5. a. Vérifier que, pour tout entier naturel non nul n, ... (partie masquée)"}'::jsonb),
    ('35be9564-0196-448f-8890-e8df4495884f'::uuid, '31fca5c9-e001-4fda-920f-9bfb90451d84'::uuid, NULL, '71ce2595-627d-4aa2-a5cb-10a47dd68053'::uuid, '2026-01-13T17:05:43.830531+00:00'::timestamp with time zone, '2026-01-13T17:11:13.810062+00:00'::timestamp with time zone, 'exercice', 'Comment étudier le signe de:   $\left(-1-x\right)\...', '{"derniere_maj":"2026-01-13T17:11:13.608Z","resolution_eleve":"x < -1\n\n\\begin{array}{c|ccccc}\nx & -\\infty & & -1 & & +\\infty \\\\\n\\hline\nf''(x) & & - & \\phi & + & \\\\\n\\hline\n& & & & & \\nearrow \\\\\nf & & \\searrow & & & \\\\\n& & & \\ln(2) & & \n\\end{array}","corrections_remarques":"✅ Travail correct"}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
    ('24a02171-8325-43b0-bb23-38904601dd84'::uuid, '31fca5c9-e001-4fda-920f-9bfb90451d84'::uuid, NULL, '71ce2595-627d-4aa2-a5cb-10a47dd68053'::uuid, '2026-01-13T18:58:28.097942+00:00'::timestamp with time zone, '2026-01-13T19:11:06.810522+00:00'::timestamp with time zone, 'exercice', 'Comment je montre par recurrence une inégalité qui...', '{"derniere_maj":"2026-01-13T19:01:17.492Z","enonce_exercice":"\\textbf{Exercice 1} \\quad \\checkmark \\hfill \\textbf{3 points}\n\nCet exercice est un questionnaire à choix multiples. Pour chacune des questions suivantes, un seule des réponses proposées est exacte. Le candidat portera sur sa copie le numéro de la question ainsi que la lettre correspondant à la réponse choisie. Chaque réponse devra être justifiée. Une réponse exacte et justifiée rapporte 1 point. Une réponse inexacte, non justifiée ou l''absence de réponse ne rapporte aucun point et n''en enlève aucun.\n\n1. Le calcul de $\\binom{7}{5}$ vaut :\n(a) 21 \\quad (b) 35 \\quad (c) 42 \\quad (d) 20\n\n2. Le nombre de résultats possibles quand on lance un dé cubique trois fois de suite est :\n(a) 1000 \\quad (b) 18 \\quad (c) 216 \\quad (d) 120\n\n3. Dans un bureau de 27 personnes, combien de façons y a-t-il de choisir un \\underline{président}, un \\underline{trésorier}, un \\underline{secrétaire} et un \\underline{vice président}?\n(a) \\sout{24 \\times 4} \\quad (b) \\sout{27^4} \\quad (c) $\\binom{27}{4}$ \\quad (d) $27 \\times 26 \\times 25 \\times 24$\n\n\\textbf{Exercice 2 :} \\quad \\sim \\hfill \\textbf{6 points}\n\nOn considère la fonction g définie sur l''intervalle $[0 ; 1]$ par\n$$ g(x) = 2x - x^2. $$\n\n1. Montrer que la fonction g est strictement \\underline{croissante} sur l''intervalle $\\underline{[0 ; 1]}$ et préciser les valeurs de g(0) et de g(1). \\quad \\checkmark\n\nOn considère la suite $(u_n)$ définie par $\\begin{cases} u_0 = \\frac{1}{2} \\\\ u_{n+1} = \\frac{1}{2} g(u_n) \\end{cases}$ pour tout entier naturel n.\n\n2. Calculer $\\underline{u_1}$ et $\\underline{u_2}$.\n\n3. Démontrer par \\underline{récurrence} que, pour tout entier naturel n, on a : $0 < u_n < u_{n+1} < 1$.\n\n4. En déduire que la suite $(u_n)$ est \\underline{convergente}.\n\n5. Déterminer la \\underline{limite} $\\ell$ de la suite $(u_n)$.\n\nOn considère la suite $(v_n)$ définie pour tout entier naturel n par $v_n = \\ln(1 - u_n)$.\n\n6. Démontrer que la suite $(v_n)$ est une suite géométrique de raison 2 et préciser son premier terme."}'::jsonb),
    ('d1386c8b-1fd1-4cfe-9957-6a67abeaaf38'::uuid, '31fca5c9-e001-4fda-920f-9bfb90451d84'::uuid, 'efc8d36b-5c29-44eb-8aeb-6ae9ed1dc485'::uuid, '71ce2595-627d-4aa2-a5cb-10a47dd68053'::uuid, '2026-01-13T19:11:07.426001+00:00'::timestamp with time zone, '2026-01-13T19:15:04.518441+00:00'::timestamp with time zone, 'exercice', 'Mon exo : Suites numériques', '{"derniere_maj":"2026-01-13T19:12:10.056Z","enonce_exercice":"définie par \\begin{cases} u_0 = \\frac{1}{2} \\\\ u_{n+1} = g(u_n) \\end{cases} \\text{pour tout entier}"}'::jsonb);
