    ('698be791-217a-4c95-9f01-fe44f43acb08'::uuid, '45be8e26-8733-46c8-a568-d4b869fe4b3d'::uuid, NULL, 'd7b49c1e-01f3-4586-a889-58853a529af6'::uuid, '2026-01-15T18:14:36.897855+00:00'::timestamp with time zone, '2026-01-15T18:47:41.70036+00:00'::timestamp with time zone, 'exercice', '📸 Exercice soumis via image', '{"derniere_maj":"2026-01-15T18:47:41.613Z","enonce_exercice":"\\text{... : parité}\n\n\\text{03} \\quad \\text{On considère la fonction } h \\text{ définie pour tout réel } x\n\\text{par } h(x) = (x-1)^3.\n\n\\bullet h \\text{ est-elle une fonction paire ? impaire ?}\n\n g \\text{ est définie sur } \\mathbb{R} \\text{ par: } g(x) = \\frac{x+1}{x^2+3}.\n\n\\bullet g \\text{ est-elle une fonction paire ? impaire ?}\n\n\\text{04} \\quad \\text{La fonction } f \\text{ définie par :}\n\n\\left( \\frac{x^2+x-2}{x+1} \\text{ pour } x \\ge 0 \\right."}'::jsonb);
INSERT INTO public.chats (id, user_id, exercice_id, session_id, created_at, updated_at, chat_type, titre, exercise_context) VALUES
